export async function getCompanySummary(payload = {}) {
  const company = String(payload.company || "NAVAI Demo").trim();

  return {
    ok: true,
    company,
    summary: `${company}는 이미 NAVAI 백엔드 도구에서 응답하고 있습니다.`,
    nextStep: "프런트엔드나 모바일 앱을 백엔드에 연결하세요.",
  };
